import { useRef, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';

const BULLET_SPD = 44;

export default function MatrixBullet({ id, origin, direction, playerPosRef, crouchRef, timeScaleRef, onExpire, onHit }) {
  const groupRef = useRef();
  const posRef   = useRef(origin.clone());
  const velRef   = useRef(direction.clone().normalize().multiplyScalar(BULLET_SPD));
  const lifeRef  = useRef(3.5);
  const doneRef  = useRef(false);

  // Orient the group so the trail faces back along velocity
  useEffect(() => {
    if (groupRef.current) {
      groupRef.current.position.copy(posRef.current);
      // Rotate so local +Z aligns with velocity
      const q = new THREE.Quaternion().setFromUnitVectors(
        new THREE.Vector3(0, 0, 1),
        velRef.current.clone().normalize()
      );
      groupRef.current.quaternion.copy(q);
    }
  }, []);

  useFrame((_, delta) => {
    if (doneRef.current) return;

    const ts = timeScaleRef?.current ?? 1;
    const dt = delta * ts;
    lifeRef.current -= delta; // real-time lifetime

    if (lifeRef.current <= 0) {
      doneRef.current = true;
      onExpire(id);
      return;
    }

    posRef.current.addScaledVector(velRef.current, dt);
    if (groupRef.current) groupRef.current.position.copy(posRef.current);

    // Hit detection
    const p = playerPosRef.current;
    const dx = posRef.current.x - p.x;
    const dz = posRef.current.z - p.z;
    const dy = posRef.current.y - (p.y ?? 1.78);
    const radial = Math.sqrt(dx * dx + dz * dz);
    const crouching = crouchRef?.current ?? false;
    const hitCeiling = crouching ? 1.05 : 2.1; // bullet above this height misses ducking player

    if (radial < 0.65 && dy < hitCeiling && dy > -0.4 && !doneRef.current) {
      doneRef.current = true;
      onHit(id);
    }
  });

  return (
    <group ref={groupRef}>
      {/* Core */}
      <mesh>
        <sphereGeometry args={[0.07, 6, 6]} />
        <meshStandardMaterial color="#ffffcc" emissive="#ffff00" emissiveIntensity={14} />
      </mesh>
      {/* Inner trail cylinder along +Z */}
      <mesh position={[0, 0, -0.55]}>
        <cylinderGeometry args={[0.02, 0.06, 1.1, 5]} rotation={[Math.PI / 2, 0, 0]} />
        <meshStandardMaterial color="#ff9900" emissive="#ff5500" emissiveIntensity={7}
          transparent opacity={0.55} depthWrite={false} />
      </mesh>
      {/* Outer glow trail */}
      <mesh position={[0, 0, -0.9]}>
        <cylinderGeometry args={[0.01, 0.08, 1.8, 4]} rotation={[Math.PI / 2, 0, 0]} />
        <meshStandardMaterial color="#ff6600" emissive="#ff2200" emissiveIntensity={4}
          transparent opacity={0.28} depthWrite={false} />
      </mesh>
      <pointLight color="#ffdd00" intensity={5} distance={5} />
    </group>
  );
}
