import { useRef, useEffect } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';
import { useControls } from './useControls';
import { MATRIX_DOORS, MATRIX_DOOR_DIST } from './constants';

const WALK_SPD  = 7.0;
const RUN_SPD   = 14.5;
const GRAVITY   = 26;
const JUMP_VEL  = 10.0;
const CAM_DIST  = 5.2;
const CAM_H     = 2.6;
const CAM_LOOK  = 1.3;   // look-at height offset on character
const PUNCH_DUR = 0.28;

const _fwd    = new THREE.Vector3();
const _right  = new THREE.Vector3();
const _camOff = new THREE.Vector3();
const _Y      = new THREE.Vector3(0, 1, 0);
const _lookAt = new THREE.Vector3();

// ── Neo body (animated) ───────────────────────────────────────────────────────
function NeoBody({ stateRef }) {
  const lLeg = useRef(), rLeg = useRef();
  const lArm = useRef(), rArm = useRef();
  const tilt  = useRef();
  const coat  = useRef();

  useFrame(({ clock }) => {
    const s  = stateRef.current;
    const t  = clock.elapsedTime;
    const wf = t * (s.running ? 14 : 9);
    const wa = s.moving ? (s.running ? 0.58 : 0.44) : 0;

    if (lLeg.current)  lLeg.current.rotation.x  =  Math.sin(wf) * wa;
    if (rLeg.current)  rLeg.current.rotation.x  = -Math.sin(wf) * wa;
    if (lArm.current)  lArm.current.rotation.x  = -Math.sin(wf) * wa * 0.55;

    // Punch arm
    if (rArm.current) {
      const target = s.punching
        ? -Math.PI * 0.82 * Math.sin(s.punchT * Math.PI)
        : Math.sin(wf) * wa * 0.55;
      rArm.current.rotation.x = THREE.MathUtils.lerp(rArm.current.rotation.x, target, 0.22);
    }

    // Body lean: dodge = sideways, jump = slight forward
    if (tilt.current) {
      const tz = s.dodging ? s.dodgeDir * 0.32 : 0;
      const tx = !s.grounded ? -0.16 : 0;
      tilt.current.rotation.z = THREE.MathUtils.lerp(tilt.current.rotation.z, tz, 0.13);
      tilt.current.rotation.x = THREE.MathUtils.lerp(tilt.current.rotation.x, tx, 0.12);
    }

    // Coat sway
    if (coat.current) {
      const sway = s.moving ? Math.sin(wf * 0.5) * 0.06 : 0;
      coat.current.rotation.x = THREE.MathUtils.lerp(coat.current.rotation.x, sway, 0.1);
    }
  });

  const blk = { color: '#060606', roughness: 0.65, metalness: 0.28 };
  const sk  = { color: '#a09080', roughness: 0.76 };
  const sht = { color: '#ddd8d0', roughness: 0.88 };

  return (
    <group ref={tilt}>
      {/* Torso */}
      <mesh position={[0, 1.52, 0]}>
        <boxGeometry args={[0.78, 1.0, 0.50]} />
        <meshStandardMaterial {...blk} />
      </mesh>

      {/* Trench coat lower (swaying) */}
      <group ref={coat}>
        <mesh position={[0, 0.52, 0.02]}>
          <boxGeometry args={[0.90, 1.02, 0.52]} />
          <meshStandardMaterial {...blk} />
        </mesh>
        {/* Coat flaps */}
        <mesh position={[-0.38, 0.28, 0.12]}>
          <boxGeometry args={[0.16, 0.55, 0.36]} />
          <meshStandardMaterial {...blk} />
        </mesh>
        <mesh position={[0.38, 0.28, 0.12]}>
          <boxGeometry args={[0.16, 0.55, 0.36]} />
          <meshStandardMaterial {...blk} />
        </mesh>
      </group>

      {/* Shirt collar */}
      <mesh position={[0, 1.93, 0.22]}>
        <boxGeometry args={[0.22, 0.17, 0.05]} />
        <meshStandardMaterial {...sht} />
      </mesh>

      {/* Head */}
      <mesh position={[0, 2.29, 0]}>
        <boxGeometry args={[0.50, 0.52, 0.46]} />
        <meshStandardMaterial {...sk} />
      </mesh>
      {/* Hair */}
      <mesh position={[0, 2.59, -0.01]}>
        <boxGeometry args={[0.52, 0.14, 0.48]} />
        <meshStandardMaterial color="#0a0a0a" roughness={1} />
      </mesh>
      {/* Sunglasses */}
      {[-0.13, 0.13].map((gx, i) => (
        <mesh key={i} position={[gx, 2.29, 0.25]}>
          <boxGeometry args={[0.17, 0.09, 0.03]} />
          <meshStandardMaterial color="#040404" emissive="#001818" emissiveIntensity={2}
            metalness={0.96} roughness={0.04} />
        </mesh>
      ))}
      <mesh position={[0, 2.29, 0.25]}>
        <boxGeometry args={[0.05, 0.025, 0.02]} />
        <meshStandardMaterial color="#111111" />
      </mesh>

      {/* Left arm */}
      <group ref={lArm} position={[-0.53, 1.88, 0]}>
        <mesh position={[0, -0.38, 0]}><boxGeometry args={[0.24, 0.78, 0.26]} /><meshStandardMaterial {...blk} /></mesh>
        <mesh position={[0, -0.82, 0]}><boxGeometry args={[0.22, 0.20, 0.22]} /><meshStandardMaterial color="#0c0c0c" roughness={0.4} metalness={0.3} /></mesh>
      </group>

      {/* Right arm (punch arm) */}
      <group ref={rArm} position={[0.53, 1.88, 0]}>
        <mesh position={[0, -0.38, 0]}><boxGeometry args={[0.24, 0.78, 0.26]} /><meshStandardMaterial {...blk} /></mesh>
        <mesh position={[0, -0.82, 0]}><boxGeometry args={[0.22, 0.20, 0.22]} /><meshStandardMaterial color="#0c0c0c" roughness={0.4} metalness={0.3} /></mesh>
      </group>

      {/* Left leg */}
      <group ref={lLeg} position={[-0.2, 1.02, 0]}>
        <mesh position={[0, -0.52, 0]}><boxGeometry args={[0.28, 1.04, 0.30]} /><meshStandardMaterial {...blk} /></mesh>
        <mesh position={[0, -1.1, 0.06]}><boxGeometry args={[0.30, 0.18, 0.40]} /><meshStandardMaterial color="#080808" roughness={0.4} metalness={0.5} /></mesh>
      </group>

      {/* Right leg */}
      <group ref={rLeg} position={[0.2, 1.02, 0]}>
        <mesh position={[0, -0.52, 0]}><boxGeometry args={[0.28, 1.04, 0.30]} /><meshStandardMaterial {...blk} /></mesh>
        <mesh position={[0, -1.1, 0.06]}><boxGeometry args={[0.30, 0.18, 0.40]} /><meshStandardMaterial color="#080808" roughness={0.4} metalness={0.5} /></mesh>
      </group>

      {/* Matrix rim light on shoulders */}
      {[-0.44, 0.44].map((sx, i) => (
        <mesh key={i} position={[sx, 2.06, 0]}>
          <boxGeometry args={[0.06, 0.04, 0.47]} />
          <meshStandardMaterial color="#00ff41" emissive="#00ff41" emissiveIntensity={1.1}
            transparent opacity={0.55} />
        </mesh>
      ))}
    </group>
  );
}

// ── Main player controller + TPS camera ──────────────────────────────────────
export default function PlayerCharacter({
  charPosRef,
  yawRef,
  pitchRef,
  dodgeRef,
  crouchRef,
  stateRef,
  bounds,
  paused,
  onNearDoor,
  sceneId,
}) {
  const { gl } = useThree();
  const keys     = useControls();
  const groupRef = useRef();
  const jumpRef  = useRef({ vy: 0, grounded: true });
  const punchCdRef = useRef(0);
  const nearRef  = useRef(null);

  // Pointer lock for mouse look
  useEffect(() => {
    const onMove = e => {
      if (!document.pointerLockElement) return;
      yawRef.current  -= e.movementX * 0.0022;
      pitchRef.current = THREE.MathUtils.clamp(
        pitchRef.current - e.movementY * 0.0016, -0.50, 0.42
      );
    };
    const onClick = () => {
      if (!document.pointerLockElement && !paused) gl.domElement.requestPointerLock();
    };
    document.addEventListener('mousemove', onMove);
    gl.domElement.addEventListener('click', onClick);
    return () => {
      document.removeEventListener('mousemove', onMove);
      gl.domElement.removeEventListener('click', onClick);
    };
  }, [gl, paused, yawRef, pitchRef]);

  // Jump on Space
  useEffect(() => {
    const onKey = e => {
      if (e.code === 'Space' && jumpRef.current.grounded && !paused && !dodgeRef.current.active) {
        jumpRef.current.vy = JUMP_VEL;
        jumpRef.current.grounded = false;
        stateRef.current.jumping = true;
        stateRef.current.grounded = false;
      }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [paused, dodgeRef, stateRef]);

  useFrame((state, delta) => {
    // Player always moves at real-time speed (never affected by timeScale)
    const dt  = Math.min(delta, 0.05);
    const k   = keys.current;
    const yaw = yawRef.current;
    const pos = charPosRef.current;

    const isSprinting = k.ShiftLeft || k.ShiftRight;
    const isMoving    = !paused && (k.KeyW || k.KeyS || k.KeyA || k.KeyD ||
                                    k.ArrowUp || k.ArrowDown || k.ArrowLeft || k.ArrowRight);

    // ── Movement in XZ ─────────────────────────────────────────────────────
    if (!paused) {
      _fwd.set(-Math.sin(yaw), 0, -Math.cos(yaw));
      _right.set(Math.cos(yaw), 0, -Math.sin(yaw));
      const spd = isSprinting ? RUN_SPD : WALK_SPD;

      if (k.KeyW || k.ArrowUp)    pos.addScaledVector(_fwd,    spd       * dt);
      if (k.KeyS || k.ArrowDown)  pos.addScaledVector(_fwd,   -spd * 0.55 * dt);
      if (k.KeyA || k.ArrowLeft)  pos.addScaledVector(_right, -spd * 0.75 * dt);
      if (k.KeyD || k.ArrowRight) pos.addScaledVector(_right,  spd * 0.75 * dt);
    }

    // ── Dodge impulse (also real-time) ──────────────────────────────────────
    if (dodgeRef.current.active) {
      dodgeRef.current.t -= dt;
      if (dodgeRef.current.t <= 0) {
        dodgeRef.current.active = false;
        stateRef.current.dodging = false;
      } else {
        pos.addScaledVector(dodgeRef.current.vel, dt);
      }
    }

    // ── Gravity + jump ──────────────────────────────────────────────────────
    const j = jumpRef.current;
    if (!j.grounded) j.vy -= GRAVITY * dt;
    pos.y = Math.max(0, pos.y + j.vy * dt);
    if (pos.y <= 0) {
      pos.y = 0;
      j.vy = 0;
      if (!j.grounded) { j.grounded = true; }
    }

    // ── Bounds (XZ only) ────────────────────────────────────────────────────
    pos.x = THREE.MathUtils.clamp(pos.x, bounds.xMin, bounds.xMax);
    pos.z = THREE.MathUtils.clamp(pos.z, bounds.zMin, bounds.zMax);

    // ── Crouch (Ctrl/C) ─────────────────────────────────────────────────────
    crouchRef.current = (k.ControlLeft || k.ControlRight || k.KeyC) && j.grounded;

    // ── Animation state update ──────────────────────────────────────────────
    stateRef.current.moving   = isMoving;
    stateRef.current.running  = isSprinting;
    stateRef.current.grounded = j.grounded;
    stateRef.current.jumping  = !j.grounded;
    if (j.grounded && stateRef.current.jumping === false) {
      // just landed
    }

    // Punch cd countdown
    if (punchCdRef.current > 0) punchCdRef.current -= dt;
    if (stateRef.current.punching) {
      stateRef.current.punchT += dt / PUNCH_DUR;
      if (stateRef.current.punchT >= 1) {
        stateRef.current.punching = false;
        stateRef.current.punchT   = 0;
      }
    }

    // ── Character mesh ──────────────────────────────────────────────────────
    if (groupRef.current) {
      groupRef.current.position.copy(pos);
      // Character faces direction of travel or camera yaw
      groupRef.current.rotation.y = yaw + Math.PI;
    }

    // ── TPS Camera ──────────────────────────────────────────────────────────
    // Camera sits behind and above, adjusted by pitch
    _camOff.set(0, 0, CAM_DIST);
    _camOff.applyAxisAngle(_Y, yaw);
    const pitchAdj = pitchRef.current * 1.6;
    state.camera.position.set(
      pos.x + _camOff.x,
      pos.y + CAM_H + pitchAdj * 0.4,
      pos.z + _camOff.z
    );
    _lookAt.set(pos.x, pos.y + CAM_LOOK + pitchAdj, pos.z);
    state.camera.lookAt(_lookAt);

    // ── Door proximity ──────────────────────────────────────────────────────
    if (sceneId === 'corridor' && onNearDoor) {
      let closest = null, minDz = MATRIX_DOOR_DIST;
      for (const door of MATRIX_DOORS) {
        const dz = Math.abs(pos.z - door.position.z);
        if (dz < minDz) { minDz = dz; closest = door; }
      }
      if (closest?.id !== nearRef.current?.id) {
        nearRef.current = closest;
        onNearDoor(closest);
      }
    }
  });

  return (
    <group ref={groupRef}>
      <NeoBody stateRef={stateRef} />
      {/* Ground shadow blob */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, 0.01, 0]}>
        <circleGeometry args={[0.52, 12]} />
        <meshStandardMaterial color="#000000" transparent opacity={0.3} depthWrite={false} />
      </mesh>
    </group>
  );
}
